() => {
  // 获取同花顺实时行情数据
  const codes = ['601857', '601808', '600256', '600583', '000852', '600547', '601069', '600988', '000975', '002716', '601899', '688111'];
  const results = [];

  // 尝试从页面获取数据
  const table = document.querySelector('table');
  if (table) {
    const rows = table.querySelectorAll('tbody tr');
    rows.forEach(row => {
      const cells = row.querySelectorAll('td');
      if (cells.length >= 4) {
        const code = cells[1]?.textContent?.trim();
        const name = cells[2]?.textContent?.trim();
        const price = cells[3]?.textContent?.trim();
        const changePct = cells[4]?.textContent?.trim();
        const change = cells[5]?.textContent?.trim();

        if (code && codes.includes(code)) {
          results.push({ code, name, price, changePct, change });
        }
      }
    });
  }

  return JSON.stringify(results);
}

